    _name = name_;
  }

  function _setSymbol(string memory symbol_) internal {
    _symbol = symbol_;
  }

  function _setUriPrefix(string memory uriPrefix) internal {
    _uriPrefix = uriPrefix;
  }

  function _update(
    address to,
    uint256 tokenId,
    address auth
  ) internal virtual override returns (address from) {
    from = super._update(to, tokenId, auth);

    _onUpdate(from, to, tokenId);

    return from;
  }

  function _onUpdate(
    address from,
    address to,
    uint256 tokenId
  ) internal virtual {
    _notifyTokenFactory(0x60, abi.encode(from, to, tokenId));
  }

  function _approve(
    address to,
    uint256 tokenId,
    address auth,
    bool emitEvent
  ) internal override {
    super._approve(to, tokenId, auth, emitEvent);

    _onApprove(to, tokenId, emitEvent);
  }

  function _onApprove(
    address to,
    uint256 tokenId,
    bool emitEvent
  ) internal virtual {
    if (emitEvent) {
      _notifyTokenFactory(0x61, abi.encode(_ownerOf(tokenId), to, tokenId));
    }
  }

  function _setApprovalForAll(
    address owner,
    address operator,
    bool approved
  ) internal override {
    super._setApprovalForAll(owner, operator, approved);

    _afterSetApprovalForAll(owner, operator, approved);
  }

  function _afterSetApprovalForAll(
    address owner,
    address operator,
    bool approved
  ) internal virtual {
    _notifyTokenFactory(0x62, abi.encode(owner, operator, approved));
  }
}

